import sys
class Solution:
    def solve(self, n: int, edges: list[list[int]]) -> int:
        # Kruskal's algorithm
        parent = list(range(n + 1))
        rank = [0] * (n + 1)
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(x, y):
            rx, ry = find(x), find(y)
            if rx == ry:
                return False
            if rank[rx] < rank[ry]:
                parent[rx] = ry
            elif rank[rx] > rank[ry]:
                parent[ry] = rx
            else:
                parent[ry] = rx
                rank[rx] += 1
            return True
        # filter out self-loops
        filtered = [e for e in edges if e[0] != e[1]]
        filtered.sort(key=lambda x: x[2])
        total = 0
        edges_used = 0
        for u, v, w in filtered:
            if union(u, v):
                total += w
                edges_used += 1
                if edges_used == n - 1:
                    break
        if n == 1:
            return 0
        if edges_used != n - 1:
            # signal impossible via raising
            raise ValueError("IMPOSSIBLE")
        return total
if __name__ == '__main__':
    data = sys.stdin.read().split()
    if not data:
        sys.exit(0)
    it = iter(data)
    n = int(next(it))
    m = int(next(it))
    edges = []
    for _ in range(m):
        u = int(next(it)); v = int(next(it)); w = int(next(it))
        edges.append([u, v, w])
    sol = Solution()
    try:
        ans = sol.solve(n, edges)
        print(ans)
    except ValueError as e:
        print(e.args[0])

