#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    long long solve(int n, vector<vector<long long>>& edges) {
        struct DSU {
            vector<int> p, r;
            DSU(int n): p(n+1), r(n+1,0) { iota(p.begin(), p.end(), 0); }
            int find(int x){ return p[x]==x?x:p[x]=find(p[x]); }
            bool unite(int a,int b){
                a=find(a); b=find(b);
                if(a==b) return false;
                if(r[a]<r[b]) swap(a,b);
                p[b]=a;
                if(r[a]==r[b]) r[a]++;
                return true;
            }
        } dsu(n);
        vector<array<long long,3>> es;
        es.reserve(edges.size());
        for(auto &e: edges){
            if(e[0]==e[1]) continue; // ignore self-loop
            es.push_back({e[2], e[0], e[1]}); // weight first for sorting
        }
        sort(es.begin(), es.end(), [](auto &a, auto &b){ return a[0] < b[0]; });
        long long total = 0;
        int used = 0;
        for(auto &e: es){
            long long w = e[0]; int u = (int)e[1]; int v = (int)e[2];
            if(dsu.unite(u,v)){
                total += w;
                used++;
                if(used == n-1) break;
            }
        }
        if(n==1) return 0;
        if(used != n-1) return -1; // indicate impossible
        return total;
    }
};

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n,m;
    if(!(cin>>n>>m)) return 0;
    vector<vector<long long>> edges(m, vector<long long>(3));
    for(int i=0;i<m;i++){
        cin>>edges[i][0]>>edges[i][1]>>edges[i][2];
    }
    Solution sol;
    long long ans = sol.solve(n, edges);
    if(ans==-1) cout<<"IMPOSSIBLE\n";
    else cout<<ans<<"\n";
    return 0;
}
